def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print(".", end="")
        print()
    if wlan.isconnected():
        ip = wlan.ifconfig()[0]
        print("Connected! IP:", ip)
        return ip
    else:
        print("WiFi connection failed!")
        return None


def generate_accept_key(ws_key):
    magic = ws_key.strip() + "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
    sha1_hash = hashlib.sha1(magic.encode()).digest()
    return binascii.b2a_base64(sha1_hash).decode().strip()


def parse_http_request(data):
    headers = {}
    lines = data.decode("utf-8").split("\r\n")
    request_line = lines[0] if lines else ""
    for line in lines[1:]:
        if ": " in line:
            key, value = line.split(": ", 1)
            headers[key.lower()] = value
    return request_line, headers


def send_websocket_handshake(client, headers):
    ws_key = headers.get("sec-websocket-key", "")
    accept_key = generate_accept_key(ws_key)
    response = (
        "HTTP/1.1 101 Switching Protocols\r\n"
        "Upgrade: websocket\r\n"
        "Connection: Upgrade\r\n"
        "Sec-WebSocket-Accept: " + accept_key + "\r\n"
        "\r\n"
    )
    client.send(response.encode())


def decode_websocket_frame(data):
    if len(data) < 2:
        return None, None

    opcode = data[0] & 0x0F
    masked = (data[1] & 0x80) != 0
    payload_len = data[1] & 0x7F

    offset = 2

    if payload_len == 126:
        if len(data) < 4:
            return None, None
        payload_len = struct.unpack(">H", data[2:4])[0]
        offset = 4
    elif payload_len == 127:
        if len(data) < 10:
            return None, None
        payload_len = struct.unpack(">Q", data[2:10])[0]
        offset = 10

    if masked:
        if len(data) < offset + 4:
            return None, None
        mask = data[offset:offset + 4]
        offset += 4

    if len(data) < offset + payload_len:
        return None, None

    payload = bytearray(data[offset:offset + payload_len])

    if masked:
        for i in range(payload_len):
            payload[i] ^= mask[i % 4]

    return opcode, bytes(payload)


def encode_websocket_frame(data, opcode=0x01):
    frame = bytearray()
    frame.append(0x80 | opcode)  # FIN + opcode

    payload = data.encode("utf-8") if isinstance(data, str) else data
    length = len(payload)

    if length < 126:
        frame.append(length)
    elif length < 65536:
        frame.append(126)
        frame.extend(struct.pack(">H", length))
    else:
        frame.append(127)
        frame.extend(struct.pack(">Q", length))

    frame.extend(payload)
    return bytes(frame)


def send_ws_message(client, message):
    try:
        if isinstance(message, dict):
            message = json.dumps(message)
        frame = encode_websocket_frame(message)
        client.send(frame)
        return True
    except Exception as e:
        print("Send error:", e)
        return False


def broadcast_message(message, exclude=None):
    disconnected = []
    for client in ws_clients:
        if client != exclude:
            if not send_ws_message(client, message):
                disconnected.append(client)
    for client in disconnected:
        remove_client(client)


def remove_client(client):
    if client in ws_clients:
        ws_clients.remove(client)
        print("Client removed. Total clients:", len(ws_clients))
    try:
        client.close()
    except:
        pass


def handle_command(client, command):
    action = command.get("action", "")
    response = {"status": "ok", "action": action}

    if action == "turn_on":
        led.value(1)
        device_state["led"] = True
        response["message"] = "LED turned ON"
        response["led"] = True

    elif action == "turn_off":
        led.value(0)
        device_state["led"] = False
        response["message"] = "LED turned OFF"
        response["led"] = False

    elif action == "toggle":
        new_state = not device_state["led"]
        led.value(1 if new_state else 0)
        device_state["led"] = new_state
        response["message"] = "LED toggled"
        response["led"] = new_state

    elif action == "set_brightness":
        brightness = command.get("value", 0)
        brightness = max(0, min(100, int(brightness)))
        device_state["brightness"] = brightness
        # If you have a PWM-capable pin:
        # pwm = machine.PWM(led, freq=1000)
        # pwm.duty(int(brightness * 1023 / 100))
        response["message"] = "Brightness set to {}".format(brightness)
        response["brightness"] = brightness

    elif action == "relay_on":
        device_state["relay"] = True
        response["message"] = "Relay turned ON"
        response["relay"] = True

    elif action == "relay_off":
        device_state["relay"] = False
        response["message"] = "Relay turned OFF"
        response["relay"] = False

    elif action == "get_status":
        device_state["uptime"] = time.ticks_ms() // 1000
        device_state["free_memory"] = gc_free_mem()
        device_state["clients_connected"] = len(ws_clients)
        response["state"] = device_state
        response["message"] = "Current device status"

    elif action == "restart":
        response["message"] = "Device restarting..."
        send_ws_message(client, response)
        time.sleep(1)
        machine.reset()

    elif action == "ping":
        response["message"] = "pong"
        response["timestamp"] = time.ticks_ms()

    else:
        response["status"] = "error"
        response["message"] = "Unknown action: {}".format(action)

    return response


def gc_free_mem():
    import gc
    gc.collect()
    return gc.mem_free()


