def serve_http(client, request_line):
    page = HTML_PAGE.replace("__WS_PORT__", str(WS_PORT))
    response = (
        "HTTP/1.1 200 OK\r\n"
        "Content-Type: text/html\r\n"
        "Content-Length: {}\r\n"
        "Connection: close\r\n"
        "\r\n"
    ).format(len(page))
    client.send(response.encode())
    # Send in chunks to avoid memory issues
    chunk_size = 1024
    for i in range(0, len(page), chunk_size):
        client.send(page[i:i + chunk_size].encode())
    client.close()


def handle_websocket_data(client):
    try:
        data = client.recv(1024)
        if not data:
            return False

        opcode, payload = decode_websocket_frame(data)

        if opcode is None:
            return False

        # Connection close
        if opcode == 0x08:
            print("Client sent close frame")
            # Send close frame back
            close_frame = encode_websocket_frame(b"", opcode=0x08)
            try:
                client.send(close_frame)
            except:
                pass
            return False

        # Ping - respond with pong
        if opcode == 0x09:
            pong_frame = encode_websocket_frame(payload if payload else b"", opcode=0x0A)
            client.send(pong_frame)
            return True

        # Pong - ignore
        if opcode == 0x0A:
            return True

        # Text frame
        if opcode == 0x01 and payload:
            try:
                message = payload.decode("utf-8")
                print("Received:", message)
                command = json.loads(message)
                response = handle_command(client, command)
                send_ws_message(client, response)

                # Broadcast state changes to all other clients
                if response.get("status") == "ok" and response.get("action") != "get_status":
                    broadcast_msg = {
                        "type": "state_update",
                        "action": response.get("action"),
                        "state": device_state
                    }
                    broadcast_message(broadcast_msg, exclude=client)

            except json.JSONDecodeError:
                error_resp = {"status": "error", "message": "Invalid JSON"}
                send_ws_message(client, error_resp)
            except Exception as e:
                print("Command error:", e)
                error_resp = {"status": "error", "message": str(e)}
                send_ws_message(client, error_resp)

        return True

    except OSError as e:
        print("Socket error:", e)
        return False
    except Exception as e:
        print("Handle error:", e)
        return False


def start_server(ip):
    import gc

    server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server.bind(("0.0.0.0", WS_PORT))
    server.listen(5)
    server.setblocking(False)

    print("WebSocket server started on ws://{}:{}".format(ip, WS_PORT))
    print("Open http://{}:{} in your browser".format(ip, WS_PORT))

    last_ping_time = time.ticks_ms()
    PING_INTERVAL = 30000  # 30 seconds

    while True:
        # Accept new connections
        try:
            client, addr = server.accept()
            print("New connection from:", addr)
            client.setblocking(True)
            client.settimeout(5.0)

            try:
                data = client.recv(2048)
                if data:
                    request_line, headers = parse_http_request(data)

                    # Check if WebSocket upgrade request
                    upgrade = headers.get("upgrade", "").lower()
                    if upgrade == "websocket":
                        send_websocket_handshake(client, headers)
                        client.setblocking(False)
                        ws_clients.append(client)
                        print("WebSocket client connected. Total:", len(ws_clients))

                        # Send welcome message
                        welcome = {
                            "type": "welcome",
                            "message": "Connected to ESP32 IoT Device",
                            "device_id": binascii.hexlify(machine.unique_id()).decode()
                        }
                        send_ws_message(client, welcome)
                    else:
                        # Serve HTTP page
                        serve_http(client, request_line)
                else:
                    client.close()
            except Exception as e:
                print("Handshake error:", e)
                try:
                    client.close()
                except:
                    pass

        except OSError:
            pass  # No new connections (non-blocking)

        # Handle existing WebSocket clients
        disconnected = []
        for client in ws_clients:
            try:
                if not handle_websocket_data(client):
                    # Check if it was a real disconnect or just no data
                    pass
            except OSError as e:
                err_num = e.args[0] if e.args else 0
                if err_num == 11:  # EAGAIN - no data available
                    continue
                print("Client error:", e)
                disconnected.append(client)
            except Exception as e:
                print("Client error:", e)
                disconnected.append(client)

        for client in disconnected:
            remove_client(client)

        # Periodic ping to keep connections alive
        current_time = time.ticks_ms()
        if time.ticks_diff(current_time, last_ping_time) > PING_INTERVAL:
            last_ping_time = current_time
            ping_frame = encode_websocket_frame(b"ping", opcode=0x09)
            dead_clients = []
            for client in ws_clients:
                try:
                    client.send(ping_frame)
                except:
                    dead_clients.append(client)
            for client in dead_clients:
                remove_client(client)

            # Garbage collection
            gc.collect()

        time.sleep_ms(10)  # Small delay to prevent CPU hogging


def main():
    import gc
    gc.collect()

    print("=" * 40)
    print("ESP32 IoT WebSocket Server")
    print("=" * 40)

    ip = connect_wifi()
    if ip:
        start_server(ip)
    else:
        print("Cannot start server without WiFi")
        print("Restarting in 10 seconds...")
        time.sleep(10)
        machine.reset()


if __name__ == "__main__":
    main()